import { useState } from "react";
import { connectDatabase } from "../api";

const EXAMPLES = [
  { label: "Supabase", icon: "⚡", value: "postgresql://postgres:password@db.xxx.supabase.co:5432/postgres" },
  { label: "PostgreSQL", icon: "🐘", value: "postgresql://user:password@localhost:5432/mydb" },
  { label: "MySQL", icon: "🐬", value: "mysql+pymysql://user:password@localhost:3306/mydb" },
  { label: "SQLite", icon: "📁", value: "sqlite:///path/to/file.db" },
];

export default function ConnectionScreen({ onConnected }) {
  const [connStr, setConnStr] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [focused, setFocused] = useState(false);

  const handleConnect = async () => {
    if (!connStr.trim()) return;
    setLoading(true); setError("");
    try {
      const data = await connectDatabase(connStr.trim());
      onConnected(data);
    } catch (e) {
      setError(e.response?.data?.detail || "Connection failed. Check your connection string.");
    } finally { setLoading(false); }
  };

  return (
    <div style={S.page}>
      {/* Ambient blobs */}
      <div style={{ ...S.blob, top: "-20%", left: "-10%", background: "rgba(91,141,239,0.07)" }} />
      <div style={{ ...S.blob, bottom: "-20%", right: "-10%", background: "rgba(139,92,246,0.07)" }} />

      <div style={S.card} className="fade-up">
        {/* Brand */}
        <div style={S.brand}>
          <div style={S.brandIcon}>
            <svg width="26" height="26" viewBox="0 0 28 28" fill="none">
              <circle cx="14" cy="14" r="12.5" stroke="url(#bg)" strokeWidth="1.5"/>
              <defs><linearGradient id="bg" x1="0" y1="0" x2="28" y2="28" gradientUnits="userSpaceOnUse"><stop stopColor="#5b8def"/><stop offset="1" stopColor="#8b5cf6"/></linearGradient></defs>
              <path d="M8 19 L12 9 L16 15 L20 7" stroke="#5b8def" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="20" cy="7" r="2.2" fill="#8b5cf6"/>
            </svg>
          </div>
          <div>
            <h1 style={S.brandName}>Talking BI</h1>
            <p style={S.brandTag}>AI-Powered Business Intelligence</p>
          </div>
        </div>

        <div style={S.divider} />

        <h2 style={S.heading}>Connect your database</h2>
        <p style={S.sub}>Supports PostgreSQL, MySQL, SQLite and more</p>

        {/* Input */}
        <div style={{ ...S.inputBox, ...(focused ? S.inputBoxFocused : {}) }}>
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none" style={{ flexShrink: 0 }}>
            <rect x="1.5" y="3.5" width="13" height="9" rx="1.5" stroke="var(--text3)" strokeWidth="1.3"/>
            <path d="M5 7.5h6M5 10h4" stroke="var(--text3)" strokeWidth="1.3" strokeLinecap="round"/>
          </svg>
          <input
            style={S.input}
            placeholder="postgresql://user:password@host:5432/dbname"
            value={connStr}
            onChange={(e) => setConnStr(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleConnect()}
            onFocus={() => setFocused(true)}
            onBlur={() => setFocused(false)}
            spellCheck={false}
          />
        </div>

        {/* Quick fill */}
        <p style={S.quickLabel}>Quick fill</p>
        <div style={S.quickRow}>
          {EXAMPLES.map((ex) => (
            <button key={ex.label} style={S.quickBtn} onClick={() => setConnStr(ex.value)}>
              <span style={S.quickIcon}>{ex.icon}</span>
              {ex.label}
            </button>
          ))}
        </div>

        {/* Error */}
        {error && (
          <div style={S.error}>
            <svg width="14" height="14" viewBox="0 0 14 14" fill="none" style={{ flexShrink: 0 }}>
              <circle cx="7" cy="7" r="6" stroke="#ef4444" strokeWidth="1.3"/>
              <path d="M7 4v3.5M7 9.5v.5" stroke="#ef4444" strokeWidth="1.3" strokeLinecap="round"/>
            </svg>
            {error}
          </div>
        )}

        {/* Connect */}
        <button
          style={{ ...S.btn, ...(loading ? S.btnLoading : {}) }}
          onClick={handleConnect}
          disabled={loading || !connStr.trim()}
        >
          {loading ? (
            <><span style={S.spinner} /> Connecting...</>
          ) : (
            <>
              <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                <path d="M3 8h10M8 3l5 5-5 5" stroke="#fff" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
              Connect Database
            </>
          )}
        </button>

        <p style={S.hint}>🔒 Connection string stays local — never stored or shared</p>
      </div>
    </div>
  );
}

const S = {
  page: { minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", padding: "24px", position: "relative", overflow: "hidden" },
  blob: { position: "fixed", width: "600px", height: "600px", borderRadius: "50%", filter: "blur(80px)", pointerEvents: "none" },
  card: { background: "var(--bg2)", border: "1px solid var(--border)", borderRadius: "var(--radius-xl)", padding: "44px 48px", width: "100%", maxWidth: "520px", position: "relative", zIndex: 1, boxShadow: "0 0 0 1px rgba(91,141,239,0.08), 0 40px 80px rgba(0,0,0,0.5)" },
  brand: { display: "flex", alignItems: "center", gap: "14px", marginBottom: "28px" },
  brandIcon: { width: "50px", height: "50px", background: "rgba(91,141,239,0.1)", border: "1px solid rgba(91,141,239,0.18)", borderRadius: "14px", display: "flex", alignItems: "center", justifyContent: "center" },
  brandName: { fontSize: "24px", fontWeight: 800, color: "#fff", letterSpacing: "-0.5px" },
  brandTag: { fontSize: "11px", color: "var(--text2)", textTransform: "uppercase", letterSpacing: "0.08em", marginTop: "2px" },
  divider: { height: "1px", background: "var(--border)", marginBottom: "28px" },
  heading: { fontSize: "20px", fontWeight: 700, color: "#fff", marginBottom: "6px" },
  sub: { fontSize: "13px", color: "var(--text2)", marginBottom: "22px" },
